export const handler = async (input) => {
  const prisonerAllergies = input.prisonerInfo?.foodAllergies || [];
  const productAllergensStr = input.productInfo?.product?.allergens || '';
  const productAllergens = productAllergensStr ? productAllergensStr.split(',').map(a => a.trim().toLowerCase()) : [];

  console.log(prisonerAllergies)
  console.log(productAllergensStr)



   const allergenMapping = {
    'celery': 'FOOD_ALLERGY_CELERY',
    'gluten': 'FOOD_ALLERGY_GLUTEN',
    'crustaceans': 'FOOD_ALLERGY_CRUSTACEANS',
    'egg': 'FOOD_ALLERGY_EGG',
    'eggs': 'FOOD_ALLERGY_EGG',
    'fish': 'FOOD_ALLERGY_FISH',
    'lupin': 'FOOD_ALLERGY_LUPIN',
    'milk': 'FOOD_ALLERGY_MILK',
    'dairy': 'FOOD_ALLERGY_MILK',
    'molluscs': 'FOOD_ALLERGY_MOLLUSCS',
    'mollusks': 'FOOD_ALLERGY_MOLLUSCS',
    'mustard': 'FOOD_ALLERGY_MUSTARD',
    'peanut': 'FOOD_ALLERGY_PEANUTS',
    'peanuts': 'FOOD_ALLERGY_PEANUTS',
    'sesame': 'FOOD_ALLERGY_SESAME',
    'soya': 'FOOD_ALLERGY_SOYA',
    'soybeans': 'FOOD_ALLERGY_SOYA',
    'soy': 'FOOD_ALLERGY_SOYA',
    'sulphur': 'FOOD_ALLERGY_SULPHUR_DIOXIDE',
    'sulfur': 'FOOD_ALLERGY_SULPHUR_DIOXIDE',
    'sulphur dioxide': 'FOOD_ALLERGY_SULPHUR_DIOXIDE',
    'sulfur dioxide': 'FOOD_ALLERGY_SULPHUR_DIOXIDE',
    'tree nuts': 'FOOD_ALLERGY_TREE_NUTS',
    'tree-nuts': 'FOOD_ALLERGY_TREE_NUTS',
    'nuts': 'FOOD_ALLERGY_TREE_NUTS'
  };

  const matchedAllergens = [];
  for (const productAllergen of productAllergens) {
    const mappedAllergen = allergenMapping[productAllergen];
    if (mappedAllergen && prisonerAllergies.includes(mappedAllergen)) {
      matchedAllergens.push({
        productAllergen: productAllergen,
        prisonerAllergy: mappedAllergen
      });
    }
  }

  const allergenRestrictionReason = matchedAllergens.length > 0 
    ? 'Product contains allergens: ' + matchedAllergens.map(m => m.productAllergen).join(', ')
    : null;

  return {
    hasAllergenConflict: matchedAllergens.length > 0,
    matchedAllergens: matchedAllergens,
    allergenRestrictionReason: allergenRestrictionReason
  };
};

export const handler = async (input) => {
  const medicalDiets = input.prisonerInfo?.medicalDietaryRequirements || [];

  console.log(medicalDiets)

  const productAllergensStr = input.product?.allergens || '';
  const productAllergens = productAllergensStr ? productAllergensStr.split(',').map(a => a.trim().toLowerCase()) : [];

  const dietaryConflicts = [];

  if (medicalDiets.includes('MEDICAL_DIET_COELIAC')) {
    const hasGluten = productAllergens.includes('gluten');

    if (hasGluten) {
      dietaryConflicts.push({
        requirement: 'MEDICAL_DIET_COELIAC',
        conflict: 'Product contains gluten'
      });
    }
  }

  if (medicalDiets.includes('MEDICAL_DIET_LACTOSE_INTOLERANT')) {
    const hasLactose = productAllergens.includes('milk') || 
                       productAllergens.includes('dairy') ||
                       productAllergens.includes('lactose');

    if (hasLactose) {
      dietaryConflicts.push({
        requirement: 'MEDICAL_DIET_LACTOSE_INTOLERANT',
        conflict: 'Product contains lactose/dairy'
      });
    }
  }

  const dietaryRestrictionReason = dietaryConflicts.length > 0
    ? dietaryConflicts.map(c => c.conflict).join('; ')
    : null;

  return {
    hasDietaryConflict: dietaryConflicts.length > 0,
    dietaryConflicts: dietaryConflicts,
    dietaryRestrictionReason: dietaryRestrictionReason
  };
};
